-- name: InsertPendingArtifact :one
-- Inserts a row in `pending` status ahead of the agent's upload. The
-- storage_key is generated by the caller (UUID-based) so the row's id and
-- the backend's object key are decoupled — makes it safe to retry without
-- ending up with orphan objects keyed off a stale PK.
INSERT INTO artifacts (
    run_id, job_run_id, pipeline_id, project_id,
    path, storage_key, expires_at
) VALUES (
    $1, $2, $3, $4,
    $5, $6, $7
)
RETURNING id, run_id, job_run_id, pipeline_id, project_id,
          path, storage_key, status, expires_at, created_at;

-- name: MarkArtifactReady :execrows
-- Called after the server HEADs the storage and confirms the object is
-- there. Bumps status + records size/sha. Safe to call once; subsequent
-- calls update nothing (status already 'ready'), returning 0 rows.
UPDATE artifacts
SET status = 'ready',
    size_bytes = $2,
    content_sha256 = $3
WHERE storage_key = $1 AND status = 'pending';

-- name: ListArtifactsByJobRun :many
-- Used by server-side JobResult reconciliation to match ArtifactRef
-- entries back to their pending rows. Also used later (E2c) to expose
-- downloads to downstream jobs in the same run.
SELECT id, run_id, job_run_id, pipeline_id, project_id,
       path, storage_key, status, size_bytes, content_sha256,
       expires_at, pinned_at, deleted_at, created_at
FROM artifacts
WHERE job_run_id = $1
ORDER BY created_at;

-- name: GetArtifactByStorageKey :one
-- Single-row lookup for the JobResult confirmation path. Returns
-- ErrNoRows if the agent invented a key or the row was swept.
SELECT id, run_id, job_run_id, pipeline_id, project_id,
       path, storage_key, status, size_bytes, content_sha256,
       expires_at, pinned_at, deleted_at, created_at
FROM artifacts
WHERE storage_key = $1;

-- name: ListArtifactsByRun :many
-- Used by E2c for intra-run downloads (`needs_artifacts:` resolution).
-- Only returns ready artefacts — pending/deleting must not leak as
-- dependable to downstream jobs.
SELECT id, run_id, job_run_id, pipeline_id, project_id,
       path, storage_key, status, size_bytes, content_sha256,
       expires_at, pinned_at, deleted_at, created_at
FROM artifacts
WHERE run_id = $1 AND status = 'ready'
  AND deleted_at IS NULL
ORDER BY created_at;

-- name: ListArtifactsWithJobByRun :many
-- Same as ListArtifactsByRun but joined with job_runs.name so the UI
-- can group artefacts by the job that produced them without an extra
-- per-artifact lookup. Returns ALL statuses — callers filter as needed.
SELECT a.id, a.run_id, a.job_run_id, a.pipeline_id, a.project_id,
       a.path, a.storage_key, a.status, a.size_bytes, a.content_sha256,
       a.expires_at, a.pinned_at, a.deleted_at, a.created_at,
       jr.name AS job_name
FROM artifacts a
JOIN job_runs jr ON jr.id = a.job_run_id
WHERE a.run_id = $1 AND a.deleted_at IS NULL
ORDER BY jr.name, a.path;

-- name: ListReadyArtifactsByRunAndJobName :many
-- Returns ready artefacts produced by a specific job name within a run,
-- optionally filtered by a path whitelist. Used by the scheduler when
-- resolving `needs_artifacts` on a downstream job. An empty paths
-- array returns all of that job's artefacts.
SELECT a.id, a.run_id, a.job_run_id, a.pipeline_id, a.project_id,
       a.path, a.storage_key, a.status, a.size_bytes, a.content_sha256,
       a.expires_at, a.pinned_at, a.deleted_at, a.created_at,
       jr.name AS job_name
FROM artifacts a
JOIN job_runs jr ON jr.id = a.job_run_id
WHERE a.run_id = $1
  AND jr.name  = $2
  AND a.status = 'ready'
  AND a.deleted_at IS NULL
  AND (cardinality($3::text[]) = 0 OR a.path = ANY($3::text[]))
ORDER BY a.path;

-- name: ClaimArtifactsForSweep :many
-- Atomically marks a bounded batch of artefacts as 'deleting' and
-- returns their storage keys so the sweeper can call Store.Delete and
-- then remove the DB row.
--
-- Two populations get claimed:
--   1) Freshly-expired rows: status='ready' AND expires_at < now() AND
--      not pinned. Standard TTL sweep.
--   2) Rows left in 'deleting' for longer than the grace window — the
--      previous sweeper crashed between "marked deleting" and "storage
--      delete + row removed". We pick those up and retry idempotently.
--
-- FOR UPDATE SKIP LOCKED makes this safe to run from multiple
-- schedulers/sweepers at once; each gets a disjoint batch.
UPDATE artifacts
SET status = 'deleting', deleted_at = NOW()
WHERE id IN (
    SELECT id FROM artifacts
    WHERE pinned_at IS NULL
      AND (
          (status = 'ready'
              AND expires_at IS NOT NULL
              AND expires_at < NOW())
          OR
          (status = 'deleting'
              AND deleted_at < NOW() - make_interval(mins => $2::int))
      )
    ORDER BY COALESCE(expires_at, deleted_at)
    LIMIT $1
    FOR UPDATE SKIP LOCKED
)
RETURNING id, storage_key, size_bytes;

-- name: RemoveArtifactRow :execrows
-- Called by the sweeper AFTER Store.Delete succeeded (or the object
-- was already gone). Removes the DB row.
DELETE FROM artifacts WHERE id = $1;

-- name: ExpireArtifactsBeyondKeepLast :execrows
-- Keep-last policy: per pipeline, rank the runs that produced
-- non-deleted artefacts by recency (run.created_at DESC); any run
-- beyond position N has ALL its non-pinned artefacts stamped with
-- expires_at = NOW(). The next TTL sweep picks them up. Pinned rows
-- are exempt; pinned runs don't consume a "slot" — they live forever
-- orthogonally to the N budget.
WITH ranked AS (
  SELECT DISTINCT a.run_id, a.pipeline_id, r.created_at,
    row_number() OVER (
      PARTITION BY a.pipeline_id
      ORDER BY r.created_at DESC
    ) AS rn
  FROM artifacts a
  JOIN runs r ON r.id = a.run_id
  WHERE a.deleted_at IS NULL AND a.pinned_at IS NULL
)
UPDATE artifacts
SET expires_at = NOW()
WHERE run_id IN (SELECT run_id FROM ranked WHERE rn > $1::int)
  AND deleted_at IS NULL
  AND pinned_at IS NULL
  AND (expires_at IS NULL OR expires_at > NOW());

-- name: ListProjectsOverArtifactQuota :many
-- Projects whose total live artefact bytes (pending + ready, non-
-- deleted, non-pinned) exceed the configured soft cap. Returned once
-- per tick so the sweeper can ExpireOldestInProjectByExcess against
-- each one individually.
SELECT a.project_id, COALESCE(SUM(a.size_bytes), 0)::bigint AS bytes
FROM artifacts a
WHERE a.deleted_at IS NULL
  AND a.pinned_at IS NULL
  AND a.status IN ('pending', 'ready')
GROUP BY a.project_id
HAVING COALESCE(SUM(a.size_bytes), 0) > $1::bigint;

-- name: ExpireOldestInProjectByExcess :execrows
-- Stamp expires_at = NOW() on the oldest non-pinned rows in a project,
-- stopping as soon as the demoted bytes cover `excess`. Uses a window
-- function so the cut-off is computed against the cumulative-up-to-
-- but-not-including-this-row (so we always demote enough, never
-- less).
WITH running AS (
  SELECT a.id,
    COALESCE(SUM(a.size_bytes) OVER (
      ORDER BY a.created_at ASC
      ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING
    ), 0)::bigint AS cum_prev
  FROM artifacts a
  WHERE a.project_id = @pid::uuid
    AND a.deleted_at IS NULL AND a.pinned_at IS NULL
    AND a.status IN ('pending', 'ready')
)
UPDATE artifacts
SET expires_at = NOW()
WHERE id IN (SELECT id FROM running WHERE cum_prev < @excess::bigint);

-- name: GlobalArtifactUsage :one
-- Total live artefact bytes. Returns 0 when the artifacts table is
-- empty. Used for the global hard cap.
SELECT COALESCE(SUM(size_bytes), 0)::bigint AS bytes
FROM artifacts
WHERE deleted_at IS NULL
  AND pinned_at IS NULL
  AND status IN ('pending', 'ready');

-- name: ExpireOldestGloballyByExcess :execrows
WITH running AS (
  SELECT a.id,
    COALESCE(SUM(a.size_bytes) OVER (
      ORDER BY a.created_at ASC
      ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING
    ), 0)::bigint AS cum_prev
  FROM artifacts a
  WHERE a.deleted_at IS NULL AND a.pinned_at IS NULL
    AND a.status IN ('pending', 'ready')
)
UPDATE artifacts
SET expires_at = NOW()
WHERE id IN (SELECT id FROM running WHERE cum_prev < $1::bigint);

-- name: GetRunUpstreamContext :one
-- For a downstream run, extracts upstream_run_id + upstream pipeline
-- name from cause_detail JSON. Empty string / null UUID when this run
-- was NOT triggered by an upstream material (cause is 'webhook' /
-- 'manual'). Caller checks upstream_run_id.Valid.
SELECT
  NULLIF(cause_detail->>'upstream_run_id',  '')::uuid AS upstream_run_id,
  (COALESCE(cause_detail->>'upstream_pipeline', ''))::text AS upstream_pipeline
FROM runs WHERE id = $1;

-- name: GetJobRunParents :one
-- Resolves pipeline_id + project_id + agent_id for a (job_run_id,
-- run_id) pair. Used by the RequestArtifactUpload handler to authorise
-- + derive the FKs. Returns ErrNoRows if job_run_id doesn't belong to
-- the claimed run_id. agent_id is NULL when the job hasn't been
-- dispatched yet (shouldn't happen on this code path but the column
-- nullability forces us to handle it).
SELECT r.pipeline_id AS pipeline_id,
       p.project_id  AS project_id,
       jr.agent_id   AS agent_id
FROM job_runs jr
JOIN runs r       ON r.id = jr.run_id
JOIN pipelines p  ON p.id = r.pipeline_id
WHERE jr.id = $1 AND jr.run_id = $2;
